import { useEffect, useLayoutEffect, useRef, useState } from "react";

/* Emscripten module factory type — generated by MODULARIZE=1 */
type BananaEngineModule = {
  ccall: (name: string, returnType: string, argTypes: string[], args: unknown[]) => unknown;
  cwrap: (name: string, returnType: string, argTypes: string[]) => (...args: unknown[]) => unknown;
};

function resolveFallbackEngineVersion(): string {
  const env = (import.meta as { env?: Record<string, string | undefined> }).env;
  const configured = env?.VITE_ENGINE_ASSET_VERSION;
  if (configured) return configured;
  if (env?.DEV) return `dev-${Date.now()}`;
  return "unknown";
}

declare global {
  interface Window {
    BananaEngine?: (config: {
      canvas: HTMLCanvasElement;
      locateFile?: (path: string, prefix: string) => string;
    }) => Promise<BananaEngineModule>;
    __bananaEngineModule?: BananaEngineModule;
  }
}

type EngineStatus = "idle" | "loading" | "running" | "error" | "unavailable";

type ContextMenuState = {
  visible: boolean;
  x: number;
  y: number;
  normalizedX: number;
  normalizedY: number;
};

type ContextMenuAction = {
  label: string;
  actionId: string;
};

type RadialControlState = {
  visible: boolean;
  x: number;
  y: number;
  activeDirection: "up" | "down" | "left" | "right" | null;
};

const RADIAL_RADIUS = 60;
const RADIAL_INNER_RADIUS = 20;
const DIRECTION_THRESHOLD = 0.35;

const MOVEMENT_KEYS = new Set([
  "w",
  "a",
  "s",
  "d",
  "arrowup",
  "arrowleft",
  "arrowdown",
  "arrowright",
]);

export function isMovementKey(key: string): boolean {
  return MOVEMENT_KEYS.has(key.toLowerCase());
}

export function computeMoveAxes(keys: ReadonlySet<string>): { moveX: number; moveZ: number } {
  const moveX =
    (keys.has("d") || keys.has("arrowright") ? 1 : 0) +
    (keys.has("a") || keys.has("arrowleft") ? -1 : 0);
  const moveZ =
    (keys.has("w") || keys.has("arrowup") ? 1 : 0) +
    (keys.has("s") || keys.has("arrowdown") ? -1 : 0);
  return { moveX, moveZ };
}

export function computeContextMenuPosition(
  clientX: number,
  clientY: number,
  viewportWidth: number,
  viewportHeight: number,
  menuWidth = 220,
  menuHeight = 140,
  padding = 8
): { x: number; y: number } {
  const safeX = Math.min(clientX, viewportWidth - menuWidth - padding);
  const safeY = Math.min(clientY, viewportHeight - menuHeight - padding);
  return { x: Math.max(padding, safeX), y: Math.max(padding, safeY) };
}

export function getDirectionFromTouch(
  touchX: number,
  touchY: number,
  radialCenterX: number,
  radialCenterY: number
): "up" | "down" | "left" | "right" | null {
  const deltaX = touchX - radialCenterX;
  const deltaY = touchY - radialCenterY;
  const distance = Math.sqrt(deltaX * deltaX + deltaY * deltaY);

  if (distance < RADIAL_INNER_RADIUS) {
    return null;
  }

  if (distance / RADIAL_RADIUS < DIRECTION_THRESHOLD) {
    return null;
  }

  const angle = Math.atan2(deltaY, deltaX);
  const normalizedAngle = ((angle * 180) / Math.PI + 360) % 360;

  if (normalizedAngle < 45 || normalizedAngle >= 315) return "right";
  if (normalizedAngle < 135) return "down";
  if (normalizedAngle < 225) return "left";
  return "up";
}

const CONTEXT_MENU_ACTIONS: ContextMenuAction[] = [
  { label: "Interact", actionId: "interact" },
  { label: "Harvest", actionId: "harvest" },
];

/* Asset rendering now fully handled by C/WASM engine */

/**
 * GameEnginePage — Pure C/WASM viewport
 *
 * React serves as a minimal container only. All viewport sizing, scaling,
 * and responsive behavior is handled directly by the WASM engine from C code.
 * No Tailwind/CSS styling constraints on the primary canvas.
 *
 * Future: HUD overlays (menu, status, controls) scaffold separately if needed.
 */
export function GameEnginePage() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const viewportRef = useRef<HTMLDivElement>(null);
  const moduleRef = useRef<BananaEngineModule | null>(null);
  const intervalRef = useRef<number>(0);
  const scriptRef = useRef<HTMLScriptElement | null>(null);
  const activeKeysRef = useRef<Set<string>>(new Set());
  const keyDownHandlerRef = useRef<((event: KeyboardEvent) => void) | null>(null);
  const keyUpHandlerRef = useRef<((event: KeyboardEvent) => void) | null>(null);
  const blurHandlerRef = useRef<(() => void) | null>(null);
  const visibilityHandlerRef = useRef<(() => void) | null>(null);
  const touchStartHandlerRef = useRef<((event: TouchEvent) => void) | null>(null);
  const touchMoveHandlerRef = useRef<((event: TouchEvent) => void) | null>(null);
  const touchEndHandlerRef = useRef<((event: TouchEvent) => void) | null>(null);
  const pointerDownHandlerRef = useRef<((event: PointerEvent) => void) | null>(null);
  const pointerMoveHandlerRef = useRef<((event: PointerEvent) => void) | null>(null);
  const pointerUpHandlerRef = useRef<((event: PointerEvent) => void) | null>(null);
  const activePointerIdRef = useRef<number | null>(null);
  const touchStartTimerRef = useRef<number>(0);
  const activeTouchIdRef = useRef<number | null>(null);
  const radialKeysRef = useRef<Set<string>>(new Set());

  const [status, setStatus] = useState<EngineStatus>("idle");
  const [error, setError] = useState<string | null>(null);
  const [contextMenu, setContextMenu] = useState<ContextMenuState>({
    visible: false,
    x: 0,
    y: 0,
    normalizedX: 0,
    normalizedY: 0,
  });
  const [radialControl, setRadialControl] = useState<RadialControlState>({
    visible: false,
    x: 0,
    y: 0,
    activeDirection: null,
  });
  const [interactionMessage, setInteractionMessage] = useState<string | null>(null);
  const [engineAssetVersion, setEngineAssetVersion] = useState<string>("pending");

  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    const viewport = viewportRef.current;
    if (!canvas || !viewport) return;

    const syncCanvasCssSize = () => {
      const bounds = viewport.getBoundingClientRect();
      const cssWidth = Math.max(1, Math.floor(bounds.width));
      const cssHeight = Math.max(1, Math.floor(bounds.height));
      const dpr = Math.max(1, window.devicePixelRatio || 1);
      const pixelWidth = Math.max(1, Math.floor(cssWidth * dpr));
      const pixelHeight = Math.max(1, Math.floor(cssHeight * dpr));
      canvas.style.width = `${cssWidth}px`;
      canvas.style.height = `${cssHeight}px`;
      if (canvas.width !== pixelWidth) {
        canvas.width = pixelWidth;
      }
      if (canvas.height !== pixelHeight) {
        canvas.height = pixelHeight;
      }
    };

    syncCanvasCssSize();

    const observer = new ResizeObserver(() => {
      syncCanvasCssSize();
    });
    observer.observe(viewport);

    window.addEventListener("resize", syncCanvasCssSize);
    return () => {
      observer.disconnect();
      window.removeEventListener("resize", syncCanvasCssSize);
    };
  }, []);

  useEffect(() => {
    const env = (import.meta as { env?: Record<string, unknown> }).env;
    const isDev = Boolean(env?.DEV);
    if (!isDev) return;
    if (window.location.hostname === "app.example") return;

    let lastVersion: string | null = null;
    const pollForWasmChanges = async () => {
      try {
        const response = await fetch(`/wasm/engine.version.json?dev-watch=${Date.now()}`, {
          cache: "no-store",
        });
        if (!response.ok) return;

        const payload = (await response.json()) as { engineAssetVersion?: string };
        const currentVersion = payload.engineAssetVersion;
        if (!currentVersion) return;

        if (lastVersion === null) {
          lastVersion = currentVersion;
          return;
        }

        if (currentVersion !== lastVersion) {
          window.location.reload();
        }
      } catch {
        /* best-effort dev polling; ignore transient fetch errors */
      }
    };

    const watcher = window.setInterval(() => {
      void pollForWasmChanges();
    }, 3000);

    return () => {
      window.clearInterval(watcher);
    };
  }, []);

  useEffect(() => {
    if (window.location.hostname === "app.example") {
      setEngineAssetVersion(resolveFallbackEngineVersion());
      return;
    }

    let canceled = false;

    const loadEngineVersion = async () => {
      try {
        const response = await fetch(`/wasm/engine.version.json?meta=${Date.now()}`, {
          cache: "no-store",
        });
        if (!response.ok) {
          if (!canceled) setEngineAssetVersion(resolveFallbackEngineVersion());
          return;
        }
        const payload = (await response.json()) as { engineAssetVersion?: string };
        if (!canceled && payload.engineAssetVersion) {
          setEngineAssetVersion(payload.engineAssetVersion);
        } else if (!canceled) {
          setEngineAssetVersion(resolveFallbackEngineVersion());
        }
      } catch {
        if (!canceled) {
          setEngineAssetVersion(resolveFallbackEngineVersion());
        }
      }
    };

    void loadEngineVersion();
    return () => {
      canceled = true;
    };
  }, []);

  /* C/WASM engine handles all asset rendering */

  const runContextAction = (actionId: string) => {
    const mod = moduleRef.current;
    if (!mod) {
      setInteractionMessage("Action unavailable: engine not ready.");
      setContextMenu((prev) => ({ ...prev, visible: false }));
      return;
    }

    const result = Number(
      mod.ccall(
        "engine_handle_right_click_normalized",
        "number",
        ["number", "number"],
        [contextMenu.normalizedX, contextMenu.normalizedY]
      )
    );

    if (result === 1) {
      setInteractionMessage(`${actionId}: applied to nearest actor.`);
    } else {
      setInteractionMessage(`${actionId}: no target in range.`);
    }
    setContextMenu((prev) => ({ ...prev, visible: false }));
  };

  useEffect(() => {
    if (engineAssetVersion === "pending") return;

    const canvas = canvasRef.current;
    if (!canvas) return;

    setStatus("loading");

    const startEngine = async () => {
      if (!window.BananaEngine) {
        setStatus("error");
        setError("BananaEngine factory not found after script load");
        return;
      }

      try {
        const mod = await window.BananaEngine({
          canvas,
          locateFile: (path, prefix) => `${prefix}${path}?v=${engineAssetVersion}`,
        });
        moduleRef.current = mod;
        window.__bananaEngineModule = mod;

        const keyDown = (event: KeyboardEvent) => {
          const key = event.key.toLowerCase();
          if (key === "escape") {
            setContextMenu((prev) => ({ ...prev, visible: false }));
            return;
          }
          if (isMovementKey(key)) {
            activeKeysRef.current.add(key);
            event.preventDefault();
            setContextMenu((prev) => ({ ...prev, visible: false }));
          }
        };

        const keyUp = (event: KeyboardEvent) => {
          const key = event.key.toLowerCase();
          activeKeysRef.current.delete(key);
        };

        const clearMovementIntent = () => {
          activeKeysRef.current.clear();
          radialKeysRef.current.clear();
          mod.ccall("engine_set_move_input", "null", ["number", "number"], [0, 0]);
          setRadialControl({ visible: false, x: 0, y: 0, activeDirection: null });
        };

        const onBlur = () => {
          clearMovementIntent();
        };

        const onVisibilityChange = () => {
          if (document.hidden) {
            clearMovementIntent();
          }
        };

        /* Touch handlers for mobile radial movement control */
        const onTouchStart = (event: TouchEvent) => {
          if (event.touches.length === 0) return;

          const touch = event.touches[0];
          activeTouchIdRef.current = touch.identifier;

          const bounds = viewportRef.current?.getBoundingClientRect();
          const touchX = bounds ? touch.clientX - bounds.left : touch.clientX;
          const touchY = bounds ? touch.clientY - bounds.top : touch.clientY;

          /* Show radial after brief hold (150ms) */
          touchStartTimerRef.current = window.setTimeout(() => {
            setRadialControl({
              visible: true,
              x: touchX,
              y: touchY,
              activeDirection: null,
            });
          }, 150);
        };

        const onTouchMove = (event: TouchEvent) => {
          if (activeTouchIdRef.current === null) return;

          const touch = Array.from(event.touches).find(
            (t) => t.identifier === activeTouchIdRef.current
          );
          if (!touch) return;

          const bounds = viewportRef.current?.getBoundingClientRect();
          const touchX = bounds ? touch.clientX - bounds.left : touch.clientX;
          const touchY = bounds ? touch.clientY - bounds.top : touch.clientY;

          setRadialControl((prev) => {
            if (!prev.visible) return prev;

            const direction = getDirectionFromTouch(touchX, touchY, prev.x, prev.y);

            /* Update active keys based on direction */
            if (direction !== prev.activeDirection) {
              radialKeysRef.current.clear();

              if (direction === "up") {
                radialKeysRef.current.add("w");
              } else if (direction === "down") {
                radialKeysRef.current.add("s");
              } else if (direction === "left") {
                radialKeysRef.current.add("a");
              } else if (direction === "right") {
                radialKeysRef.current.add("d");
              }
            }

            return { ...prev, activeDirection: direction };
          });
        };

        const onTouchEnd = (event: TouchEvent) => {
          const touch = Array.from(event.changedTouches).find(
            (t) => t.identifier === activeTouchIdRef.current
          );
          if (!touch) return;

          window.clearTimeout(touchStartTimerRef.current);
          activeTouchIdRef.current = null;
          radialKeysRef.current.clear();
          setRadialControl({ visible: false, x: 0, y: 0, activeDirection: null });
        };

        const onPointerDown = (event: PointerEvent) => {
          if (event.pointerType === "mouse") return;

          activePointerIdRef.current = event.pointerId;

          const bounds = viewportRef.current?.getBoundingClientRect();
          const touchX = bounds ? event.clientX - bounds.left : event.clientX;
          const touchY = bounds ? event.clientY - bounds.top : event.clientY;

          window.clearTimeout(touchStartTimerRef.current);
          touchStartTimerRef.current = window.setTimeout(() => {
            setRadialControl({
              visible: true,
              x: touchX,
              y: touchY,
              activeDirection: null,
            });
          }, 150);
        };

        const onPointerMove = (event: PointerEvent) => {
          if (activePointerIdRef.current !== event.pointerId) return;

          const bounds = viewportRef.current?.getBoundingClientRect();
          const touchX = bounds ? event.clientX - bounds.left : event.clientX;
          const touchY = bounds ? event.clientY - bounds.top : event.clientY;

          setRadialControl((prev) => {
            if (!prev.visible) return prev;

            const direction = getDirectionFromTouch(touchX, touchY, prev.x, prev.y);

            if (direction !== prev.activeDirection) {
              radialKeysRef.current.clear();

              if (direction === "up") {
                radialKeysRef.current.add("w");
              } else if (direction === "down") {
                radialKeysRef.current.add("s");
              } else if (direction === "left") {
                radialKeysRef.current.add("a");
              } else if (direction === "right") {
                radialKeysRef.current.add("d");
              }
            }

            return { ...prev, activeDirection: direction };
          });
        };

        const onPointerUp = (event: PointerEvent) => {
          if (activePointerIdRef.current !== event.pointerId) return;

          window.clearTimeout(touchStartTimerRef.current);
          activePointerIdRef.current = null;
          radialKeysRef.current.clear();
          setRadialControl({ visible: false, x: 0, y: 0, activeDirection: null });
        };

        keyDownHandlerRef.current = keyDown;
        keyUpHandlerRef.current = keyUp;
        blurHandlerRef.current = onBlur;
        visibilityHandlerRef.current = onVisibilityChange;
        touchStartHandlerRef.current = onTouchStart;
        touchMoveHandlerRef.current = onTouchMove;
        touchEndHandlerRef.current = onTouchEnd;
        pointerDownHandlerRef.current = onPointerDown;
        pointerMoveHandlerRef.current = onPointerMove;
        pointerUpHandlerRef.current = onPointerUp;
        window.addEventListener("keydown", keyDown, { capture: true });
        window.addEventListener("keyup", keyUp, { capture: true });
        window.addEventListener("blur", onBlur);
        document.addEventListener("visibilitychange", onVisibilityChange);
        window.addEventListener("touchstart", onTouchStart, { passive: true });
        window.addEventListener("touchmove", onTouchMove, { passive: true });
        window.addEventListener("touchend", onTouchEnd, { passive: true });
        window.addEventListener("pointerdown", onPointerDown, { passive: true });
        window.addEventListener("pointermove", onPointerMove, { passive: true });
        window.addEventListener("pointerup", onPointerUp, { passive: true });
        window.addEventListener("pointercancel", onPointerUp, { passive: true });
        setStatus("running");

        const fpsLoop = () => {
          const combinedKeys = new Set([...activeKeysRef.current, ...radialKeysRef.current]);
          const { moveX, moveZ } = computeMoveAxes(combinedKeys);
          mod.ccall("engine_set_move_input", "null", ["number", "number"], [moveX, moveZ]);
          mod.ccall("engine_tick", "number", ["number"], [1 / 60]);
        };
        intervalRef.current = window.setInterval(fpsLoop, 16);
      } catch (e) {
        setStatus("error");
        setError(e instanceof Error ? e.message : "Engine initialization failed");
      }
    };

    if (typeof window.BananaEngine === "function") {
      void startEngine();
    } else {
      /* Dynamically load engine.js built by scripts/build-engine-wasm.sh */
      const script = document.createElement("script");
      script.src = `/wasm/engine.js?v=${engineAssetVersion}`;
      scriptRef.current = script;

      script.onerror = () => {
        setStatus("unavailable");
        setError(
          "engine.js not found. Run: bash scripts/build-engine-wasm.sh (requires Emscripten SDK)"
        );
      };

      script.onload = () => {
        void startEngine();
      };

      document.head.appendChild(script);
    }

    return () => {
      window.clearInterval(intervalRef.current);
      window.clearTimeout(touchStartTimerRef.current);
      if (keyDownHandlerRef.current) {
        window.removeEventListener("keydown", keyDownHandlerRef.current, { capture: true });
        keyDownHandlerRef.current = null;
      }
      if (keyUpHandlerRef.current) {
        window.removeEventListener("keyup", keyUpHandlerRef.current, { capture: true });
        keyUpHandlerRef.current = null;
      }
      if (blurHandlerRef.current) {
        window.removeEventListener("blur", blurHandlerRef.current);
        blurHandlerRef.current = null;
      }
      if (visibilityHandlerRef.current) {
        document.removeEventListener("visibilitychange", visibilityHandlerRef.current);
        visibilityHandlerRef.current = null;
      }
      if (touchStartHandlerRef.current) {
        window.removeEventListener("touchstart", touchStartHandlerRef.current);
        touchStartHandlerRef.current = null;
      }
      if (touchMoveHandlerRef.current) {
        window.removeEventListener("touchmove", touchMoveHandlerRef.current);
        touchMoveHandlerRef.current = null;
      }
      if (touchEndHandlerRef.current) {
        window.removeEventListener("touchend", touchEndHandlerRef.current);
        touchEndHandlerRef.current = null;
      }
      if (pointerDownHandlerRef.current) {
        window.removeEventListener("pointerdown", pointerDownHandlerRef.current);
        pointerDownHandlerRef.current = null;
      }
      if (pointerMoveHandlerRef.current) {
        window.removeEventListener("pointermove", pointerMoveHandlerRef.current);
        pointerMoveHandlerRef.current = null;
      }
      if (pointerUpHandlerRef.current) {
        window.removeEventListener("pointerup", pointerUpHandlerRef.current);
        window.removeEventListener("pointercancel", pointerUpHandlerRef.current);
        pointerUpHandlerRef.current = null;
      }
      activeKeysRef.current.clear();
      radialKeysRef.current.clear();
      activePointerIdRef.current = null;
      scriptRef.current?.remove();
      delete window.__bananaEngineModule;
      moduleRef.current = null;
      /* Module shutdown is handled internally by Emscripten on unload */
    };
  }, [engineAssetVersion]);

  const showSplash = status === "idle" || status === "loading";

  return (
    <div
      ref={viewportRef}
      style={{
        position: "fixed",
        inset: 0,
        width: "100vw",
        height: "100dvh",
        margin: 0,
        padding: 0,
        overflow: "hidden",
        backgroundColor: "#000",
      }}
    >
      {/* Splash loading overlay — visible while WASM engine initializes */}
      {showSplash && (
        <>
          <style>{`
            @keyframes potassium-pulse {
              0%, 100% { opacity: 0.35; letter-spacing: 0.18em; }
              50%       { opacity: 1;    letter-spacing: 0.28em; }
            }
            @keyframes potassium-fadein {
              from { opacity: 0; transform: scale(0.97); }
              to   { opacity: 1; transform: scale(1); }
            }
          `}</style>
          <div
            style={{
              position: "absolute",
              inset: 0,
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              justifyContent: "center",
              background: "radial-gradient(ellipse at 50% 60%, #1a1400 0%, #000 70%)",
              zIndex: 2000,
              animation: "potassium-fadein 0.4s ease both",
              gap: 0,
            }}
          >
            <img
              src="/splash.png"
              alt="Banana Engine — Peel-Powered Performance"
              style={{
                width: "min(560px, 90vw)",
                height: "auto",
                imageRendering: "auto",
                filter: "drop-shadow(0 0 40px rgba(210,160,0,0.35))",
                userSelect: "none",
                pointerEvents: "none",
              }}
            />
            <div
              style={{
                marginTop: 8,
                fontFamily: "'Arial Black', Impact, sans-serif",
                fontSize: "clamp(11px, 1.8vw, 16px)",
                fontWeight: 900,
                color: "#d4a800",
                letterSpacing: "0.18em",
                textTransform: "uppercase",
                animation: "potassium-pulse 1.6s ease-in-out infinite",
              }}
            >
              Initializing
            </div>
            <div
              style={{
                marginTop: 10,
                fontFamily: "monospace",
                fontSize: "clamp(9px, 1.1vw, 11px)",
                color: "rgba(255,255,255,0.3)",
                letterSpacing: "0.06em",
                textTransform: "uppercase",
              }}
            >
              100% Potassium Powered · Natural Fuel Efficiency · Low Emissions*
            </div>
            <div
              style={{
                marginTop: 4,
                fontFamily: "monospace",
                fontSize: "clamp(8px, 0.9vw, 10px)",
                color: "rgba(255,255,255,0.15)",
                letterSpacing: "0.05em",
              }}
            >
              *Exhaust may contain potassium
            </div>
          </div>
        </>
      )}
      {/* Primary WASM viewport — 100% coverage, responsive sizing handled by C engine */}
      <canvas
        ref={canvasRef}
        onContextMenu={(event) => {
          event.preventDefault();
          const bounds = viewportRef.current?.getBoundingClientRect();
          const relativeX = bounds ? event.clientX - bounds.left : event.clientX;
          const relativeY = bounds ? event.clientY - bounds.top : event.clientY;
          const viewportWidth = bounds?.width ?? window.innerWidth;
          const viewportHeight = bounds?.height ?? window.innerHeight;
          const pos = computeContextMenuPosition(
            relativeX,
            relativeY,
            viewportWidth,
            viewportHeight
          );
          const normalizedX = viewportWidth > 0 ? relativeX / viewportWidth : 0;
          const normalizedY = viewportHeight > 0 ? relativeY / viewportHeight : 0;
          setContextMenu({
            visible: true,
            x: pos.x,
            y: pos.y,
            normalizedX,
            normalizedY,
          });
        }}
        style={{
          display: "block",
          width: "100%",
          height: "100%",
          imageRendering: "pixelated",
        }}
      />
      {/* Error HUD overlay (future: menu/status integration point) */}
      {(status === "error" || status === "unavailable") && error && (
        <div
          style={{
            position: "absolute",
            bottom: 16,
            left: 16,
            maxWidth: 320,
            padding: 12,
            backgroundColor: "rgba(30, 24, 24, 0.8)",
            border: "1px solid rgba(239, 68, 68, 0.3)",
            borderRadius: 6,
            color: "rgba(254, 226, 226, 1)",
            fontSize: 14,
            fontFamily: "monospace",
            zIndex: 1000,
          }}
        >
          {error}
        </div>
      )}

      <div
        style={{
          position: "absolute",
          top: 16,
          left: "50%",
          transform: "translateX(-50%)",
          padding: "10px 14px",
          background: "linear-gradient(180deg, rgba(17,17,24,0.82) 0%, rgba(9,9,12,0.72) 100%)",
          border: "1px solid rgba(255, 210, 102, 0.35)",
          borderRadius: 8,
          color: "rgba(255, 255, 255, 0.95)",
          fontSize: 12,
          fontFamily: "monospace",
          lineHeight: 1.45,
          zIndex: 1000,
          pointerEvents: "none",
          whiteSpace: "pre-line",
          textAlign: "center",
          letterSpacing: "0.03em",
          boxShadow: "0 8px 24px rgba(0,0,0,0.38)",
        }}
      >
        {
          "ARPG Controls\nWASD / Arrow Keys: Move\nMobile: Hold to show radial\nRight Click: Action menu"
        }
      </div>

      {contextMenu.visible && (
        <button
          type="button"
          aria-label="Close action menu"
          onMouseDown={() => setContextMenu((prev) => ({ ...prev, visible: false }))}
          style={{
            position: "absolute",
            inset: 0,
            border: "none",
            padding: 0,
            margin: 0,
            background: "transparent",
            zIndex: 1100,
            cursor: "default",
          }}
        />
      )}

      {contextMenu.visible && (
        <div
          style={{
            position: "absolute",
            top: contextMenu.y,
            left: contextMenu.x,
            width: 220,
            padding: 8,
            backgroundColor: "rgba(18, 18, 22, 0.96)",
            border: "1px solid rgba(255, 255, 255, 0.2)",
            borderRadius: 8,
            boxShadow: "0 12px 28px rgba(0, 0, 0, 0.45)",
            color: "rgba(255, 255, 255, 0.94)",
            fontSize: 13,
            fontFamily: "monospace",
            zIndex: 1200,
          }}
        >
          <div style={{ padding: "4px 6px", opacity: 0.85, fontWeight: 700 }}>Actions</div>
          {CONTEXT_MENU_ACTIONS.map((action) => (
            <button
              key={action.actionId}
              type="button"
              onClick={() => runContextAction(action.actionId)}
              style={{
                width: "100%",
                textAlign: "left",
                border: "none",
                background: "transparent",
                color: "rgba(255, 255, 255, 0.9)",
                padding: "8px 6px",
                fontFamily: "monospace",
                cursor: "pointer",
              }}
            >
              {action.label}
            </button>
          ))}
          <button
            type="button"
            onClick={() => setContextMenu((prev) => ({ ...prev, visible: false }))}
            style={{
              width: "100%",
              textAlign: "left",
              border: "none",
              background: "transparent",
              color: "rgba(255, 255, 255, 0.9)",
              padding: "8px 6px",
              fontFamily: "monospace",
              cursor: "pointer",
            }}
          >
            Close
          </button>
        </div>
      )}

      {/* Mobile radial movement control */}
      {radialControl.visible && (
        <div
          data-testid="mobile-radial-control"
          style={{
            position: "absolute",
            left: radialControl.x - RADIAL_RADIUS,
            top: radialControl.y - RADIAL_RADIUS,
            width: RADIAL_RADIUS * 2,
            height: RADIAL_RADIUS * 2,
            pointerEvents: "none",
            zIndex: 800,
          }}
        >
          <svg
            aria-label="Mobile movement radial"
            role="img"
            width={RADIAL_RADIUS * 2}
            height={RADIAL_RADIUS * 2}
            viewBox={`0 0 ${RADIAL_RADIUS * 2} ${RADIAL_RADIUS * 2}`}
            style={{ position: "absolute" }}
          >
            <title>Mobile movement radial</title>
            {/* Outer circle background */}
            <circle
              cx={RADIAL_RADIUS}
              cy={RADIAL_RADIUS}
              r={RADIAL_RADIUS}
              fill="rgba(0, 0, 0, 0.4)"
              stroke="rgba(255, 255, 255, 0.2)"
              strokeWidth="1"
            />

            {/* Inner circle (dead zone) */}
            <circle
              cx={RADIAL_RADIUS}
              cy={RADIAL_RADIUS}
              r={RADIAL_INNER_RADIUS}
              fill="rgba(255, 255, 255, 0.05)"
              stroke="rgba(255, 255, 255, 0.15)"
              strokeWidth="1"
            />

            {/* Direction indicators */}
            {/* Up (W) */}
            <path
              d={`M ${RADIAL_RADIUS} ${RADIAL_INNER_RADIUS} L ${RADIAL_RADIUS + 12} ${RADIAL_INNER_RADIUS + 15} L ${RADIAL_RADIUS} ${RADIAL_RADIUS - 5} L ${RADIAL_RADIUS - 12} ${RADIAL_INNER_RADIUS + 15} Z`}
              fill={
                radialControl.activeDirection === "up"
                  ? "rgba(100, 200, 255, 0.8)"
                  : "rgba(255, 255, 255, 0.2)"
              }
              stroke="rgba(255, 255, 255, 0.3)"
              strokeWidth="0.5"
            />

            {/* Down (S) */}
            <path
              d={`M ${RADIAL_RADIUS} ${RADIAL_RADIUS + RADIAL_INNER_RADIUS + 5} L ${RADIAL_RADIUS + 12} ${RADIAL_RADIUS - RADIAL_INNER_RADIUS - 15} L ${RADIAL_RADIUS} ${RADIAL_RADIUS + 5} L ${RADIAL_RADIUS - 12} ${RADIAL_RADIUS - RADIAL_INNER_RADIUS - 15} Z`}
              fill={
                radialControl.activeDirection === "down"
                  ? "rgba(100, 200, 255, 0.8)"
                  : "rgba(255, 255, 255, 0.2)"
              }
              stroke="rgba(255, 255, 255, 0.3)"
              strokeWidth="0.5"
            />

            {/* Left (A) */}
            <path
              d={`M ${RADIAL_INNER_RADIUS} ${RADIAL_RADIUS} L ${RADIAL_INNER_RADIUS + 15} ${RADIAL_RADIUS - 12} L ${RADIAL_RADIUS - 5} ${RADIAL_RADIUS} L ${RADIAL_INNER_RADIUS + 15} ${RADIAL_RADIUS + 12} Z`}
              fill={
                radialControl.activeDirection === "left"
                  ? "rgba(100, 200, 255, 0.8)"
                  : "rgba(255, 255, 255, 0.2)"
              }
              stroke="rgba(255, 255, 255, 0.3)"
              strokeWidth="0.5"
            />

            {/* Right (D) */}
            <path
              d={`M ${RADIAL_RADIUS + RADIAL_INNER_RADIUS + 5} ${RADIAL_RADIUS} L ${RADIAL_RADIUS - RADIAL_INNER_RADIUS - 15} ${RADIAL_RADIUS - 12} L ${RADIAL_RADIUS + 5} ${RADIAL_RADIUS} L ${RADIAL_RADIUS - RADIAL_INNER_RADIUS - 15} ${RADIAL_RADIUS + 12} Z`}
              fill={
                radialControl.activeDirection === "right"
                  ? "rgba(100, 200, 255, 0.8)"
                  : "rgba(255, 255, 255, 0.2)"
              }
              stroke="rgba(255, 255, 255, 0.3)"
              strokeWidth="0.5"
            />

            {/* Center touch indicator */}
            <circle cx={RADIAL_RADIUS} cy={RADIAL_RADIUS} r="4" fill="rgba(255, 255, 255, 0.3)" />
          </svg>

          {/* Labels */}
          <div
            data-testid="mobile-radial-up"
            style={{
              position: "absolute",
              top: RADIAL_INNER_RADIUS - 8,
              left: "50%",
              transform: "translateX(-50%)",
              fontSize: 11,
              fontFamily: "monospace",
              fontWeight: 700,
              color:
                radialControl.activeDirection === "up"
                  ? "rgba(100, 200, 255, 1)"
                  : "rgba(255, 255, 255, 0.4)",
              textShadow: "0 1px 3px rgba(0, 0, 0, 0.5)",
              pointerEvents: "none",
            }}
          >
            W
          </div>
          <div
            data-testid="mobile-radial-down"
            style={{
              position: "absolute",
              bottom: RADIAL_INNER_RADIUS - 8,
              left: "50%",
              transform: "translateX(-50%)",
              fontSize: 11,
              fontFamily: "monospace",
              fontWeight: 700,
              color:
                radialControl.activeDirection === "down"
                  ? "rgba(100, 200, 255, 1)"
                  : "rgba(255, 255, 255, 0.4)",
              textShadow: "0 1px 3px rgba(0, 0, 0, 0.5)",
              pointerEvents: "none",
            }}
          >
            S
          </div>
          <div
            data-testid="mobile-radial-left"
            style={{
              position: "absolute",
              left: RADIAL_INNER_RADIUS - 8,
              top: "50%",
              transform: "translateY(-50%)",
              fontSize: 11,
              fontFamily: "monospace",
              fontWeight: 700,
              color:
                radialControl.activeDirection === "left"
                  ? "rgba(100, 200, 255, 1)"
                  : "rgba(255, 255, 255, 0.4)",
              textShadow: "0 1px 3px rgba(0, 0, 0, 0.5)",
              pointerEvents: "none",
            }}
          >
            A
          </div>
          <div
            data-testid="mobile-radial-right"
            style={{
              position: "absolute",
              right: RADIAL_INNER_RADIUS - 8,
              top: "50%",
              transform: "translateY(-50%)",
              fontSize: 11,
              fontFamily: "monospace",
              fontWeight: 700,
              color:
                radialControl.activeDirection === "right"
                  ? "rgba(100, 200, 255, 1)"
                  : "rgba(255, 255, 255, 0.4)",
              textShadow: "0 1px 3px rgba(0, 0, 0, 0.5)",
              pointerEvents: "none",
            }}
          >
            D
          </div>
        </div>
      )}

      {interactionMessage && (
        <div
          style={{
            position: "absolute",
            bottom: 16,
            right: 16,
            padding: "8px 10px",
            backgroundColor: "rgba(0, 0, 0, 0.6)",
            border: "1px solid rgba(255, 255, 255, 0.2)",
            borderRadius: 6,
            color: "rgba(255, 255, 255, 0.9)",
            fontSize: 12,
            fontFamily: "monospace",
            zIndex: 1000,
          }}
        >
          {interactionMessage}
        </div>
      )}

      {/* Engine version debug badge */}
      <div
        style={{
          position: "absolute",
          bottom: interactionMessage ? 72 : 16,
          right: 16,
          padding: "4px 8px",
          backgroundColor: "rgba(0, 0, 0, 0.4)",
          border: "1px solid rgba(255, 255, 255, 0.1)",
          borderRadius: 4,
          color: "rgba(255, 255, 255, 0.5)",
          fontSize: 10,
          fontFamily: "monospace",
          zIndex: 999,
          pointerEvents: "none",
          letterSpacing: "0.05em",
        }}
      >
        Engine v{engineAssetVersion}
      </div>
    </div>
  );
}
